        InsertAbove: function (rl, index) {
            // 1. Find the actual position (ignoring GLOBAL if necessary)
            const insertIndex = this.rules.indexOf(rl);
            
            // 2. Prevent inserting above Rule 1 if it's the very first
            if (insertIndex === 0 && rl.version !== 'GLOBAL') {
                // Optional: logic to handle if you allow inserting at the very top
            }

            // 3. Create the new empty rule object
            const newRule = this.createNewRuleObject(rl.parent);

            // 4. Insert into the array
            this.rules.splice(insertIndex, 0, newRule);

            // 5. RECALCULATE: Use the parent prefix of the current level
            this.recalculateRules(this.rules, rl.parent);
        },

        InsertBelow: function (rl, index) {
            // 1. Find the position and insert after it
            const insertIndex = this.rules.indexOf(rl) + 1;
            
            // 2. Create the new empty rule object
            const newRule = this.createNewRuleObject(rl.parent);

            // 3. Insert into the array
            this.rules.splice(insertIndex, 0, newRule);

            // 4. RECALCULATE
            this.recalculateRules(this.rules, rl.parent);
        },

        // Helper to keep code clean
        createNewRuleObject(parentVersion) {
            return {
                ruleId: 0,
                ruleDisplayOrder: 0,
                ruleName: "", 
                version: "",
                ruleCondition: {
                    nodeName: "",
                    serviceName: "",
                    condition: ""
                },
                rules: [],
                parent: parentVersion,
                isShowChild: true,
                isDelete: false
            };
        },
